  Agents: "\u0410\u0433\u0435\u043D\u0442\u044B",
  "Choose Action": "\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435",
  "Edit {{name}}": "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C {{name}}",
  "Edit Tools: {{name}}": "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B: {{name}}",
  "Edit Color: {{name}}": "\u0420\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0446\u0432\u0435\u0442: {{name}}",
  "Delete {{name}}": "\u0423\u0434\u0430\u043B\u0438\u0442\u044C {{name}}",
