  Back: "\u041D\u0430\u0437\u0430\u0434",
  "No agent selected": "\u0410\u0433\u0435\u043D\u0442 \u043D\u0435 \u0432\u044B\u0431\u0440\u0430\u043D",
  "File Path: ": "\u041F\u0443\u0442\u044C \u043A \u0444\u0430\u0439\u043B\u0443: ",
