  "User Level (~/.qwen/agents/)": "\u0423\u0440\u043E\u0432\u0435\u043D\u044C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044F (~/.qwen/agents/)",
  "\u2705 Subagent Created Successfully!": "\u2705 \u041F\u043E\u0434\u0430\u0433\u0435\u043D\u0442 \u0443\u0441\u043F\u0435\u0448\u043D\u043E \u0441\u043E\u0437\u0434\u0430\u043D!",
  'Subagent "{{name}}" has been saved to {{level}} level.': '\u041F\u043E\u0434\u0430\u0433\u0435\u043D\u0442 "{{name}}" \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 {{level}}.',
  "Name: ": "\u0418\u043C\u044F: ",
  "Location: ": "\u0420\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435: ",
  "\u274C Error saving subagent:": "\u274C \u041E\u0448\u0438\u0431\u043A\u0430 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430:",
  "Warnings:": "\u041F\u0440\u0435\u0434\u0443\u043F\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u044F:",
  'Name "{{name}}" already exists at {{level}} level - will overwrite existing subagent': '\u0418\u043C\u044F "{{name}}" \u0443\u0436\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 {{level}} - \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442 \u0431\u0443\u0434\u0435\u0442 \u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0438\u0441\u0430\u043D',
  'Name "{{name}}" exists at user level - project level will take precedence': '\u0418\u043C\u044F "{{name}}" \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044F - \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u0431\u0443\u0434\u0435\u0442 \u0438\u043C\u0435\u0442\u044C \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442',
  'Name "{{name}}" exists at project level - existing subagent will take precedence': '\u0418\u043C\u044F "{{name}}" \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 - \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442 \u0431\u0443\u0434\u0435\u0442 \u0438\u043C\u0435\u0442\u044C \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442',
  "Description is over {{length}} characters": "\u041E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u043F\u0440\u0435\u0432\u044B\u0448\u0430\u0435\u0442 {{length}} \u0441\u0438\u043C\u0432\u043E\u043B\u043E\u0432",
  "System prompt is over {{length}} characters": "\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u043F\u0440\u043E\u043C\u043F\u0442 \u043F\u0440\u0435\u0432\u044B\u0448\u0430\u0435\u0442 {{length}} \u0441\u0438\u043C\u0432\u043E\u043B\u043E\u0432",
  // Агенты - Шаги мастера создания
  "Step {{n}}: Choose Location": "\u0428\u0430\u0433 {{n}}: \u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435",
  "Step {{n}}: Choose Generation Method": "\u0428\u0430\u0433 {{n}}: \u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u043C\u0435\u0442\u043E\u0434 \u0433\u0435\u043D\u0435\u0440\u0430\u0446\u0438\u0438",
  "Generate with Qwen Code (Recommended)": "\u0421\u0433\u0435\u043D\u0435\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E Qwen Code (\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F)",
  "Manual Creation": "\u0420\u0443\u0447\u043D\u043E\u0435 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435",
  "Describe what this subagent should do and when it should be used. (Be comprehensive for best results)": "\u041E\u043F\u0438\u0448\u0438\u0442\u0435, \u0447\u0442\u043E \u0434\u043E\u043B\u0436\u0435\u043D \u0434\u0435\u043B\u0430\u0442\u044C \u044D\u0442\u043E\u0442 \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442 \u0438 \u043A\u043E\u0433\u0434\u0430 \u0435\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C. (\u0411\u0443\u0434\u044C\u0442\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u044B \u0434\u043B\u044F \u043B\u0443\u0447\u0448\u0438\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432)",
  "e.g., Expert code reviewer that reviews code based on best practices...": "\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u042D\u043A\u0441\u043F\u0435\u0440\u0442\u043D\u044B\u0439 \u0440\u0435\u0432\u044C\u044E\u0432\u0435\u0440 \u043A\u043E\u0434\u0430, \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u044E\u0449\u0438\u0439 \u043A\u043E\u0434 \u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 \u043B\u0443\u0447\u0448\u0438\u043C \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430\u043C...",
  "Generating subagent configuration...": "\u0413\u0435\u043D\u0435\u0440\u0430\u0446\u0438\u044F \u043A\u043E\u043D\u0444\u0438\u0433\u0443\u0440\u0430\u0446\u0438\u0438 \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430...",
  "Failed to generate subagent: {{error}}": "\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u0441\u0433\u0435\u043D\u0435\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430: {{error}}",
  "Step {{n}}: Describe Your Subagent": "\u0428\u0430\u0433 {{n}}: \u041E\u043F\u0438\u0448\u0438\u0442\u0435 \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430",
  "Step {{n}}: Enter Subagent Name": "\u0428\u0430\u0433 {{n}}: \u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u0438\u043C\u044F \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430",
  "Step {{n}}: Enter System Prompt": "\u0428\u0430\u0433 {{n}}: \u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u043F\u0440\u043E\u043C\u043F\u0442",
  "Step {{n}}: Enter Description": "\u0428\u0430\u0433 {{n}}: \u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435",
  // Агенты - Выбор инструментов
  "Step {{n}}: Select Tools": "\u0428\u0430\u0433 {{n}}: \u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B",
  "All Tools (Default)": "\u0412\u0441\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B (\u043F\u043E \u0443\u043C\u043E\u043B\u0447\u0430\u043D\u0438\u044E)",
