  "Read-only Tools": "\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F",
  "Read & Edit Tools": "\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F \u0438 \u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F",
  "Read & Edit & Execution Tools": "\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F, \u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F",
  "All tools selected, including MCP tools": "\u0412\u0441\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0432\u044B\u0431\u0440\u0430\u043D\u044B, \u0432\u043A\u043B\u044E\u0447\u0430\u044F MCP tools",
  "Selected tools:": "\u0412\u044B\u0431\u0440\u0430\u043D\u043D\u044B\u0435 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B:",
  "Read-only tools:": "\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F:",
  "Edit tools:": "\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F:",
  "Execution tools:": "\u0418\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F:",
  "Step {{n}}: Choose Background Color": "\u0428\u0430\u0433 {{n}}: \u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0446\u0432\u0435\u0442 \u0444\u043E\u043D\u0430",
  "Step {{n}}: Confirm and Save": "\u0428\u0430\u0433 {{n}}: \u041F\u043E\u0434\u0442\u0432\u0435\u0440\u0434\u0438\u0442\u0435 \u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u0435",
  // Агенты - Навигация и инструкции
  "Esc to cancel": "Esc \u0434\u043B\u044F \u043E\u0442\u043C\u0435\u043D\u044B",
  "Press Enter to save, e to save and edit, Esc to go back": "Enter \u0434\u043B\u044F \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F, e \u0434\u043B\u044F \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, Esc \u0434\u043B\u044F \u0432\u043E\u0437\u0432\u0440\u0430\u0442\u0430",
  "Press Enter to continue, {{navigation}}Esc to {{action}}": "Enter \u0434\u043B\u044F \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0435\u043D\u0438\u044F, {{navigation}}Esc \u0434\u043B\u044F {{action}}",
  cancel: "\u043E\u0442\u043C\u0435\u043D\u044B",
  "go back": "\u0432\u043E\u0437\u0432\u0440\u0430\u0442\u0430",
  "\u2191\u2193 to navigate, ": "\u2191\u2193 \u0434\u043B\u044F \u043D\u0430\u0432\u0438\u0433\u0430\u0446\u0438\u0438, ",
  "Enter a clear, unique name for this subagent.": "\u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u0447\u0435\u0442\u043A\u043E\u0435, \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u043E\u0435 \u0438\u043C\u044F \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430.",
  "e.g., Code Reviewer": "\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0420\u0435\u0432\u044C\u044E\u0432\u0435\u0440 \u043A\u043E\u0434\u0430",
  "Name cannot be empty.": "\u0418\u043C\u044F \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0443\u0441\u0442\u044B\u043C.",
  "Write the system prompt that defines this subagent's behavior. Be comprehensive for best results.": "\u041D\u0430\u043F\u0438\u0448\u0438\u0442\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u043F\u0440\u043E\u043C\u043F\u0442, \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0439 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430. \u0411\u0443\u0434\u044C\u0442\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u044B \u0434\u043B\u044F \u043B\u0443\u0447\u0448\u0438\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432.",
  "e.g., You are an expert code reviewer...": "\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0412\u044B \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u043D\u044B\u0439 \u0440\u0435\u0432\u044C\u044E\u0432\u0435\u0440 \u043A\u043E\u0434\u0430...",
  "System prompt cannot be empty.": "\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u043F\u0440\u043E\u043C\u043F\u0442 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0443\u0441\u0442\u044B\u043C.",
  "Describe when and how this subagent should be used.": "\u041E\u043F\u0438\u0448\u0438\u0442\u0435, \u043A\u043E\u0433\u0434\u0430 \u0438 \u043A\u0430\u043A \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u044D\u0442\u043E\u0433\u043E \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430.",
  "e.g., Reviews code for best practices and potential bugs.": "\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u041F\u0440\u043E\u0432\u0435\u0440\u044F\u0435\u0442 \u043A\u043E\u0434 \u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 \u043B\u0443\u0447\u0448\u0438\u043C \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430\u043C \u0438 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0435 \u043E\u0448\u0438\u0431\u043A\u0438.",
  "Description cannot be empty.": "\u041E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0443\u0441\u0442\u044B\u043C.",
  "Failed to launch editor: {{error}}": "\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u0437\u0430\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0440\u0435\u0434\u0430\u043A\u0442\u043E\u0440: {{error}}",
  "Failed to save and edit subagent: {{error}}": "\u041D\u0435 \u0443\u0434\u0430\u043B\u043E\u0441\u044C \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u044C \u0438 \u043E\u0442\u0440\u0435\u0434\u0430\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043F\u043E\u0434\u0430\u0433\u0435\u043D\u0442\u0430: {{error}}",
  // ============================================================================
