  "Manage folder trust settings": "\u0423\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0430\u043C\u0438 \u0434\u043E\u0432\u0435\u0440\u0438\u044F \u043A \u043F\u0430\u043F\u043A\u0430\u043C",
  "Manage permission rules": "\u0423\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 permission rules",
  Allow: "\u0420\u0430\u0437\u0440\u0435\u0448\u0438\u0442\u044C",
  Ask: "\u0421\u043F\u0440\u043E\u0441\u0438\u0442\u044C",
