  // Строка состояния
  // ============================================================================
  "Using:": "\u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F:",
  "{{count}} open file": "{{count}} \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0439 \u0444\u0430\u0439\u043B",
  "{{count}} open files": "{{count}} \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u0444\u0430\u0439\u043B\u0430(\u043E\u0432)",
  "(ctrl+g to view)": "(ctrl+g \u0434\u043B\u044F \u043F\u0440\u043E\u0441\u043C\u043E\u0442\u0440\u0430)",
  "{{count}} {{name}} file": "{{count}} \u0444\u0430\u0439\u043B {{name}}",
